scripts.source:
const filter = $variables.filter;
params.query = filter;
params.queryFields = $variables.searchColumns;
params.pageSize ??= $datasource.config.pageSize;

// Set keys
$parameters.config?.parameters?.filter(k => k.usage === 'Key').forEach((k) => {
  params.filters[k.name] = {
    operation: 'eq',
    operator: 'and',
    value: $parameters[k.name]
  }
});

// if sorting is not on params, get it from datasource config
if (!params.sortings || params.sortings.length === 0) {
  params.sortings = $datasource.config.sort.map(i => {
    return { field: i.field, direction: (i.direction === 'Ascending' ? 'ASC' : 'DESC') }
  });
}

$variables.searchParameters = params;
const response = await $datasource.search(params, $variables.columns.map(c => c.name));

$variables.data = response.data;
$variables.page = params.pageIndex + 1;
$variables.first = params.first;
$variables.totalCount = response.totalCount;
$variables.ready = true;
return response;

